using System;using System.IO;namespace LemonFramework.UProfiler.Core{    [Serializable]    public struct DeviceInfo : IBinarySerializable    {        //Unity version        public string unityVersion;        //Operating system        public string operatingSystem;        //Device model        public string deviceModel;        //Device name        public string deviceName;        //Unique device identifier        public string deviceUniqueIdentifier;        //System memory size (MB)        public int systemMemorySize;        //Graphics memory size (MB)        public int graphicsMemorySize;        //Processor type        public string processorType;        //Processor frequency (MHz)        public int processorFrequency;        //Processor count        public int processorCount;        //Graphics device name        public string graphicsDeviceName;        //Graphics device vendor        public string graphicsDeviceVendor;        //Graphics API / driver version        public string graphicsDeviceVersion;        //Whether shadows are supported        public bool supportsShadows;        //Battery level (0-1)        public float batteryLevel;        //Screen width (pixels)        public int screenWidth;        //Screen height (pixels)        public int screenHeight;        public void DeSerialize(BinaryReader reader)        {            unityVersion = reader.ReadString();            operatingSystem = reader.ReadString();            deviceModel = reader.ReadString();            deviceName = reader.ReadString();            deviceUniqueIdentifier = reader.ReadString();            systemMemorySize = reader.ReadInt32();            graphicsMemorySize = reader.ReadInt32();            processorType = reader.ReadString();            processorFrequency = reader.ReadInt32();            processorCount = reader.ReadInt32();            graphicsDeviceName = reader.ReadString();            graphicsDeviceVendor = reader.ReadString();            graphicsDeviceVersion = reader.ReadString();            supportsShadows = reader.ReadBoolean();            batteryLevel = reader.ReadSingle();            screenWidth = reader.ReadInt32();            screenHeight = reader.ReadInt32();        }        public void Serialize(BinaryWriter writer)        {            writer.Write(unityVersion);            writer.Write(operatingSystem);            writer.Write(deviceModel);            writer.Write(deviceName);            writer.Write(deviceUniqueIdentifier);            writer.Write(systemMemorySize);            writer.Write(graphicsMemorySize);            writer.Write(processorType);            writer.Write(processorFrequency);            writer.Write(processorCount);            writer.Write(graphicsDeviceName);            writer.Write(graphicsDeviceVendor);            writer.Write(graphicsDeviceVersion);            writer.Write(supportsShadows);            writer.Write(batteryLevel);            writer.Write(screenWidth);            writer.Write(screenHeight);        }        public override string ToString()        {            return $"UnityVersion:{unityVersion}\n" + $"OperatingSystem:{operatingSystem}\n" +                   $"DeviceModel:{deviceModel}\n" + $"DeviceName:{deviceName}\n" +                   $"DeviceUniqueIdentifier:{deviceUniqueIdentifier}\n" + $"SystemMemorySize:{systemMemorySize}\n" +                   $"GraphicsMemorySize:{graphicsMemorySize}\n" + $"ProcessorType:{processorType}\n" +                   $"ProcessorFrequency:{processorFrequency}\n" + $"ProcessorCount:{processorCount}\n" +                   $"GraphicsDeviceName:{graphicsDeviceName}\n" + $"GraphicsDeviceVendor:{graphicsDeviceVendor}\n" +                   $"GraphicsDeviceVersion:{graphicsDeviceVersion}\n" + $"SupportsShadows:{supportsShadows}\n" +                   $"BatteryLevel:{batteryLevel}\n" + $"ScreenWidth:{screenWidth}\n" + $"ScreenHeight:{screenHeight}";        }    }}